import { getAuthenticationCookie } from '../lib';
import { expireCookie } from '../lib/utils/cache-utils';
import { urlWithTrailingSlash } from '../lib/utils/url-utils';

const dotenv = require('dotenv');

let username: string;
let password: string;
let appUrl: string;

beforeAll(() => {
  dotenv.config();
});

beforeAll(() => {
  username = process.env.NETIQ_AUTH_COOKIE_IPN as string;
  password = process.env.NETIQ_AUTH_COOKIE_PASSWORD as string;
  appUrl = process.env.NETIQ_AUTH_COOKIE_URL as string;
});

test('Get mod_auth_openidc_session cookie from NetIQ', async () => {
  let cookie = await getAuthenticationCookie({
    username,
    password,
    appUrl,
  });
  expect(cookie.key).toBe('mod_auth_openidc_session');
});

test('Get NetIQ mod_auth_openidc_session cookie from cache', async () => {
  let cookie = await getAuthenticationCookie({
    username,
    password,
    appUrl,
    use_cache: false,
  });
  let previous = cookie.value;
  cookie = await getAuthenticationCookie({
    username,
    password,
    appUrl,
  });
  expect(cookie.key).toBe('mod_auth_openidc_session');
  expect(cookie.value).toBe(previous);
});

test('Refresh expired NetIQ mod_auth_openidc_session cookie', async () => {
  let cookie = await getAuthenticationCookie({
    username,
    password,
    appUrl,
    use_cache: false,
  });
  let previous = cookie.value;
  const key = `${username}@${urlWithTrailingSlash(appUrl)}`;
  expireCookie(key);
  cookie = await getAuthenticationCookie({
    username,
    password,
    appUrl,
  });
  expect(cookie.key).toBe('mod_auth_openidc_session');
  expect(cookie.value).not.toBe(previous);
});

test('Incorrect credentials for NetIQ mod_auth_openidc_session cookie', async () => {
  try {
    await getAuthenticationCookie({
      username: 'incorrect',
      password: 'incorrect',
      appUrl,
    });
    expect(true).toBe(false);
  } catch (error) {
    expect((error as Error).message).toBe(
      "idp did not set 'JSESSIONID' cookie. This usually means your credentials are not valid.",
    );
  }
});
